SELECT COUNT(*) 
FROM employee_promotions 
WHERE strftime('%Y', promotion_date) = '2022';

SELECT COUNT(employee_id) AS stay_interview_count
FROM stay_interviews
WHERE stay_date > '2022-12-01';

SELECT AVG(job_satisfaction_score) AS average_job_satisfaction
FROM employees
WHERE julianday('now') - julianday(hire_date) > 365;
